async function seed() {
  await signInAnonymously(auth)
  const counts = { english: 0, maths: 0, chinese: 0 }
  console.log(`Seeding ${questions.length} questions...`)
  for (const q of questions) {
    await addDoc(collection(db, 'questionBank', q.subject, 'questions'), q)
    counts[q.subject]++
    if (counts[q.subject] % 50 === 0) console.log(`  ${q.subject}: ${counts[q.subject]}`)
  }
  console.log(`Done! English: ${counts.english}, Maths: ${counts.maths}, Chinese: ${counts.chinese}`)
  process.exit(0)
}

seed().catch(err => { console.error(err); process.exit(1) })
